/* Pure CSS Neon Glow */
@keyframes neon-flicker {
  0%, 19%, 21%, 23%, 25%, 54%, 56%, 100% {
    text-shadow:
      0 0 5px #fff,
      0 0 10px #fff,
      0 0 20px var(--glow),
      0 0 40px var(--glow),
      0 0 80px var(--glow);
  }
  20%, 24%, 55% {
    text-shadow: none;
    opacity: 0.8;
  }
}
.neon-text {
  animation: neon-flicker 2s infinite;
}
